INSERT INTO stage_prompts (stage, config) VALUES (2, '{"stage":2,"laneTitle":"Story Board","assemblyOrder":["masterSheetPrompt","yourDescription","universalStyle"],"universalStyle":{"key":"production_bible_universal","label":"Universal Production Bible Style","text":"GLOBAL ART DIRECTION\n\nEvery generated storyboard belongs to the same Production Bible.\n\nVisual Identity\n\u2022 Apple keynote quality\n\u2022 A24 cinematic minimalism\n\u2022 Pixar pre-production documentation\n\u2022 Weta Workshop production bible\n\u2022 Netflix concept art presentation\n\u2022 Cannes Lions advertising pitch deck\n\nGraphic Language\n\u2022 White premium presentation layout\n\u2022 Thin black divider lines\n\u2022 Spacious negative space\n\u2022 Editorial typography hierarchy\n\u2022 Soft paper texture\n\u2022 Production asset numbering\n\u2022 Revision labels\n\u2022 Version numbers\n\u2022 Project title placeholder\n\u2022 Copyright footer\n\nEvery storyboard should feel like it was created by an elite commercial art department."},"items":{"story":{"label":"Story","note":"content.geminiInstruction below is today''s existing guidance, unchanged for now \u2014 this pass only fixes the output instruction.","content":{"geminiInstruction":"The brief''s \"storyboard\" field, if present, is the customer''s own already-written script \u2014 it is the primary source, not something to compress into a generic pitch. Preserve its actual dialogue lines, character names, and scene beats, in the same language/script they were written in \u2014 never translate them to English. Structure the description as a numbered list of scenes/panels, one per beat from the script, so a designer can review and edit each individually \u2014 the number should match however many real beats the script has (do not force it to a fixed count). Carry the actual dialogue as an on-screen caption or spoken line wherever the script already has one.","fieldsSchema":[{"key":"concept","label":"Concept / logline","type":"textarea"},{"key":"tone","label":"Tone","type":"pill","options":["Comedic","Warm","Dramatic","Aspirational","Playful"]}],"autoPopulate":{"note":"One Story generation drafts the skeleton of every downstream stage instead of the designer re-typing every cast member/prop/scene by hand. Each array item becomes a real item in that stage, pre-filled with this description \u2014 the designer still reviews/edits/regenerates each one individually at its own stage afterward. This is new \u2014 nothing in the app reads these fields yet; wiring it up is a ''clean the code'' task.","geminiResponseFields":[{"key":"characters","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"character"}},{"key":"properties","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"property"}},{"key":"backgrounds","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"background"}},{"key":"sounds","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"sound"}},{"key":"scenes","shape":"array of {name, summary}","createsItemsIn":{"stage":4,"itemKey":"scene"}}]}},"outputInstructions":[{"key":"master_storyboard_prompt","label":"Master Storyboard Prompt","default":true,"text":"Create a premium cinematic storyboard panel based ONLY on the storyboard description provided below.\n\nOBJECTIVE\nVisualize the described scene exactly as written.\nDo not invent additional story elements.\nMaintain the described characters, props, environment, camera angle, lens, composition, emotion, action and lighting.\n\nGenerate a production-ready storyboard suitable for a world-class advertising campaign.\n\nSTYLE\n\u2022 Hollywood commercial storyboard\n\u2022 Cannes Lions presentation quality\n\u2022 Director''s storyboard\n\u2022 Hand-drawn pencil illustration\n\u2022 Marker rendering\n\u2022 Loose confident sketch lines\n\u2022 Grayscale shading\n\u2022 Slight blue storyboard pencil accents\n\u2022 Premium beige storyboard paper\n\u2022 Elegant editorial graphic design\n\nFRAME DESIGN\n\u2022 Production Title\n\u2022 Commercial Name\n\u2022 Sequence Number\n\u2022 Scene Number\n\u2022 Shot Number\n\u2022 Frame Number\n\u2022 Shot Size\n\u2022 Camera Angle\n\u2022 Lens\n\u2022 Camera Movement\n\u2022 Aspect Ratio\n\u2022 Duration\n\u2022 Time of Day\n\u2022 Location\n\u2022 Dialogue\n\u2022 Voice Over\n\u2022 Music Cue\n\u2022 Sound Effects\n\u2022 Director Notes\n\u2022 Art Director Notes\n\u2022 Lighting Notes\n\nANNOTATIONS\n\u2022 Camera movement\n\u2022 Character movement\n\u2022 Eyeline\n\u2022 Focus direction\n\u2022 Lighting direction\n\u2022 Key prop callouts\n\u2022 Performance notes\n\u2022 Emotional beat\n\u2022 Composition notes\n\u2022 Blocking\n\u2022 Screen direction\n\nCINEMATIC QUALITY\n\u2022 Rule of thirds\n\u2022 Leading lines\n\u2022 Dynamic perspective\n\u2022 Strong silhouettes\n\u2022 Foreground / Midground / Background separation\n\u2022 Dramatic lighting\n\u2022 Motivated light source\n\u2022 Shadow direction\n\u2022 Premium production presentation\n\nCOLOR\nMostly grayscale with subtle blue storyboard pencil and light beige paper.\n\nDO NOT\n\u2022 Change the story\n\u2022 Add characters\n\u2022 Change wardrobe\n\u2022 Change props\n\u2022 Cartoonize\n\u2022 Anime\n\u2022 Comic book style\n\u2022 Photorealistic painting\n\u2022 Over-render\n\nOUTPUT\nGenerate ONE premium storyboard panel that looks like it belongs inside the production bible of a multi-million-dollar commercial."}]}}}')
  ON CONFLICT(stage) DO UPDATE SET config = excluded.config, updated_at = datetime('now');

INSERT INTO stage_prompts (stage, config) VALUES (3, '{"stage":3,"laneTitle":"Visual & Music","assemblyOrder":["masterSheetPrompt","yourDescription","universalStyle"],"universalStyle":{"key":"production_bible_universal","label":"Universal Production Bible Style","text":"GLOBAL ART DIRECTION\n\nEvery generated sheet belongs to the same Production Bible.\n\nVisual Identity\n\u2022 Apple keynote quality\n\u2022 A24 cinematic minimalism\n\u2022 Pixar pre-production documentation\n\u2022 Weta Workshop production bible\n\u2022 Netflix concept art presentation\n\u2022 Cannes Lions advertising pitch deck\n\nGraphic Language\n\u2022 White premium background\n\u2022 Thin black divider lines\n\u2022 Spacious layout\n\u2022 Elegant typography\n\u2022 Soft paper texture\n\u2022 Production asset numbering\n\u2022 Version numbers\n\u2022 Revision labels\n\u2022 Project title placeholder\n\u2022 Copyright footer\n\nEvery page should feel like it was created by an elite commercial art department for a $10M production."},"items":{"character":{"label":"Character","note":"content.geminiInstruction below is today''s existing guidance, unchanged for now \u2014 this pass only fixes the output instruction. Revisit content later if needed.","content":{"geminiInstruction":"Describe the character for use as a visual reference: gender, age, skin tone, hair, outfit. A short, specific, production-usable description \u2014 not a placeholder.","fieldsSchema":[{"key":"gender","label":"Gender","type":"pill","options":["Female","Male","Non-binary"]},{"key":"age","label":"Age","type":"number"},{"key":"skin_tone","label":"Skin tone","type":"pill","options":["Fair","Wheatish","Dusky","Dark"]},{"key":"hair","label":"Hair","type":"text"},{"key":"outfit","label":"Outfit","type":"text"}]},"outputInstructions":[{"key":"master_character_sheet","label":"Master Character Sheet","default":true,"text":"Create a Premium Film Character Design Sheet based ONLY on the character description provided below.\n\nOBJECTIVE\nVisualize the described character as a production-ready asset for a high-end advertising film.\n\nART DIRECTION\n\u2022 Hollywood pre-production design bible\n\u2022 Premium concept art\n\u2022 Realistic digital painting\n\u2022 White museum-quality background\n\u2022 Luxury editorial layout\n\u2022 Apple-level presentation\n\u2022 Pixar / Weta / ILM production documentation\n\nDISPLAY\nHero Portrait\nFront / 3-4 / Side / Rear\nHead Close-up\nExpression Strip\nPose Strip\nCostume Details\nAccessories\nHands\nFootwear\nMaterial & Fabric Callouts\nColor Palette\nScale Reference\nLighting Reference\n\nANNOTATIONS\nUse elegant arrows describing clothing, materials, accessories, personality and distinguishing features.\n\nGRAPHIC DESIGN\nAsset Code \u2022 Version \u2022 Revision \u2022 Copyright Footer\n\nOUTPUT\nOne premium character sheet suitable for a Hollywood commercial production bible."}]},"property":{"label":"Property","note":"content.geminiInstruction below is today''s existing guidance, unchanged for now.","content":{"geminiInstruction":"Describe the property/prop for use as a visual reference. A short, specific, production-usable description \u2014 not a placeholder.","fieldsSchema":[{"key":"description","label":"Description","type":"textarea"}]},"outputInstructions":[{"key":"master_prop_sheet","label":"Master Prop Sheet","default":true,"text":"Create a Professional Film Prop Design Sheet based ONLY on the prop description below.\n\nSTYLE\nHollywood prop department documentation.\nLuxury industrial design.\nPhotorealistic concept rendering.\n\nDISPLAY\nHero\nFront\nBack\nLeft\nRight\nTop\nBottom\n45\u00b0 View\nClose-up Details\nMaterial Breakdown\nTexture Samples\nHuman Scale\nLighting Reference\n\nANNOTATIONS\nMaterials, finish, functional parts, usage, aging.\n\nOUTPUT\nOfficial feature-film prop package."}]},"sound":{"label":"Sound","note":"content.geminiInstruction below is today''s existing guidance, unchanged for now.","content":{"geminiInstruction":"Describe the sound/music direction for this project. A short, specific, production-usable description \u2014 not a placeholder.","fieldsSchema":[{"key":"description","label":"Description","type":"textarea"}]},"outputInstructions":[{"key":"master_music_sheet","label":"Master Music / Sound Design Sheet","default":true,"text":"Create a Professional Music & Sound Design Board based ONLY on the creative brief below.\n\nDISPLAY\nPrimary Mood\nSecondary Mood\nGenre\nTempo\nEnergy Curve\nInstrumentation\nRhythm\nScene Timing\nSound FX\nAmbient Layer\nSilence Moments\nTransition Notes\nVoice-over Mood\n\nOUTPUT\nCreative audio brief used by award-winning advertising agencies."}]},"background":{"label":"Background","note":"Reinstated per request.","content":{"geminiInstruction":"Describe the background/location for use as a visual reference: location, lighting, style. A short, specific, production-usable description \u2014 not a placeholder.","fieldsSchema":[{"key":"location","label":"Location","type":"text"},{"key":"lighting","label":"Lighting","type":"pill","options":["Morning Natural","Golden Hour","Studio Softbox","Overcast","Night Neon"]},{"key":"style","label":"Style","type":"pill","options":["Minimal","Rustic","Luxury","Industrial","Cozy"]}]},"outputInstructions":[{"key":"master_background_sheet","label":"Master Background / Location Sheet","default":true,"text":"Create a Premium Cinematic Environment Design Board based ONLY on the location description below.\n\nSTYLE\nHollywood production design.\nArchitectural visualization.\nAdvertising art direction.\n\nDISPLAY\nHero Wide\nEye Level\nBird''s-eye\nCorner Perspective\nEntrance\nDetail Views\nLighting Studies\nMorning\nAfternoon\nGolden Hour\nNight\nRain\nFog\nColor Palette\nMaterial Palette\nTexture Samples\nEnvironment Mood Board\n\nANNOTATIONS\nCamera positions\nActor movement\nLighting direction\nComposition suggestions\n\nOUTPUT\nProfessional commercial location scout package."}]}}}')
  ON CONFLICT(stage) DO UPDATE SET config = excluded.config, updated_at = datetime('now');

INSERT INTO stage_prompts (stage, config) VALUES (4, '{"stage":4,"laneTitle":"Scene Blueprint","note":"Combines the old Stage 4 (Scene) and Stage 5 (Director Shot List) into one stage, per the reference doc \u2014 one item per scene carrying both dramatic content and camera/shot fields, one deliverable image, one payment gate instead of two. Item key stays ''scene''; the old standalone ''shotlist'' item type is retired when the code catches up to this json.","assemblyOrder":["masterSheetPrompt","yourDescription","universalStyle"],"universalStyle":{"key":"production_bible_universal","label":"Universal Production Bible Style","text":"GLOBAL ART DIRECTION\nApple keynote quality, A24 minimalism, Netflix production documentation, Weta Workshop presentation, Cannes Lions pitch deck.\nPremium overlays, typography, spacing, version labels, production numbering.\nEvery image should feel like a real frame from a multi-million-dollar commercial."},"items":{"scene":{"label":"Scene","note":"fieldsSchema merges the former Scene fields (objective/location/action/dialogue/emotion/duration/broll/transition) with the former Shot List fields (type/camera/lens/movement) into one schema.","content":{"geminiInstruction":"If the brief''s \"storyboard\" field already has dialogue written for a beat matching this scene, reuse those exact lines verbatim (same language) for the \"dialogue\" field instead of inventing new ones. Also draft the camera/shot fields (type, camera, lens, movement) appropriate to this scene''s action and emotion.","fieldsSchema":[{"key":"objective","label":"Objective","type":"pill","options":["Hook","Problem","Solution","Proof","Demo","CTA"]},{"key":"location","label":"Location","type":"text"},{"key":"action","label":"Action","type":"text"},{"key":"dialogue","label":"Dialogue","type":"textarea"},{"key":"emotion","label":"Emotion","type":"pill","options":["Frustrated","Curious","Relieved","Happy","Excited","Confident","Calm"]},{"key":"duration","label":"Duration (sec)","type":"number"},{"key":"broll","label":"B-roll","type":"pill","options":["None","Product Macro Shot","Product Spin","Slow-Motion Detail","Texture Close-up","Lifestyle Cutaway"]},{"key":"transition","label":"Transition","type":"pill","options":["Hard Cut","Whip Pan","Match Cut","Fade","Zoom Transition"]},{"key":"type","label":"Shot type","type":"pill","options":["Close-up","Wide","Macro","Medium","POV","Over-the-shoulder"]},{"key":"camera","label":"Camera","type":"pill","options":["Handheld","Tripod","Gimbal","Drone"]},{"key":"lens","label":"Lens","type":"pill","options":["24mm","35mm","50mm","85mm"]},{"key":"movement","label":"Movement","type":"pill","options":["Static","Push In","Pull Out","Pan","Tilt","Whip Pan"]}]},"outputInstructions":[{"key":"master_scene_blueprint_prompt","label":"Master Scene Blueprint Prompt","default":true,"text":"Create a premium Scene Blueprint based ONLY on the scene description provided below.\n\nOBJECTIVE\nVisualize the described scene exactly as written.\nGenerate a photorealistic cinematic frame suitable for client approval before video production.\nDo not invent story elements.\nMaintain characters, props, wardrobe, environment, lighting, camera angle, emotion and blocking.\n\nSTYLE\n\u2022 Hollywood commercial frame\n\u2022 Premium advertising photography\n\u2022 Cinematic realism\n\u2022 Feature-film lighting\n\u2022 Luxury editorial presentation\n\u2022 Cannes Lions quality\n\nSCENE OVERLAYS\n\u2022 Production Title\n\u2022 Sequence Number\n\u2022 Scene Number\n\u2022 Shot Number\n\u2022 Location\n\u2022 Time of Day\n\u2022 Camera\n\u2022 Lens\n\u2022 Shot Size\n\u2022 Camera Angle\n\u2022 Camera Movement\n\u2022 Dialogue (subtitle style)\n\u2022 Character Names\n\u2022 Mood\n\u2022 Duration\n\u2022 Director Notes\n\u2022 Art Director Notes\n\u2022 Lighting Notes\n\nCOMPOSITION\n\u2022 Rule of thirds\n\u2022 Leading lines\n\u2022 Foreground/Midground/Background separation\n\u2022 Natural depth\n\u2022 Cinematic color grading\n\u2022 Motivated lighting\n\nDO NOT\nChange story, characters, props or wardrobe. No cartoon, anime or comic styles.\n\nOUTPUT\nOne premium Scene Blueprint image for commercial pre-production."}]}}}')
  ON CONFLICT(stage) DO UPDATE SET config = excluded.config, updated_at = datetime('now');

INSERT INTO stage_prompts (stage, config) VALUES (5, '{"stage":5,"laneTitle":"Final Movie","note":"Kept per-scene, as confirmed \u2014 each scene generates its own clip independently; stitching all scene clips into one finished commercial happens externally, outside this tool. The source doc describes a single whole-project ''Final Production Render'' assembling every approved stage at once \u2014 adapted below to per-scene scope: ''this scene''s Blueprint/Character/Prop/Background Sheets + Music Brief'' instead of the whole project''s. Cross-scene concerns (adding new scenes, transitions between scenes) trimmed out since they don''t apply to a single clip.","assemblyOrder":["masterSheetPrompt","yourDescription","universalStyle"],"universalStyle":{"key":"production_bible_universal","label":"Universal Production Bible Style","text":"Maintain one consistent visual identity.\n\n\u2022 Apple keynote presentation quality\n\u2022 Cannes Lions commercial quality\n\u2022 Netflix production consistency\n\u2022 Weta Workshop attention to detail\n\nThe final video must feel like it was directed by an award-winning commercial director and produced by a premium production house."},"items":{"movie":{"label":"Final Movie Clip","note":"content.geminiInstruction is new \u2014 there was no specific backend guidance for ''movie'' before this (it only got the generic instruction).","content":{"geminiInstruction":"Draft the animation direction (camera movement, pacing, duration) for turning this scene''s approved key-frame into a short video clip, maintaining continuity with the scene''s established characters, wardrobe, props, lighting, and the approved Music Brief.","fieldsSchema":[{"key":"direction","label":"Animation direction","type":"textarea"},{"key":"duration","label":"Duration (sec)","type":"number"}]},"outputInstructions":[{"key":"master_final_production_render_prompt","label":"Master Final Production Render Prompt (per scene)","default":true,"text":"Create this scene''s final commercial-quality clip exactly from its approved Scene Blueprint.\n\nOBJECTIVE\n\nExecute this scene''s approved Scene Blueprint without inventing new story elements.\nMaintain complete continuity with the Character Sheets, Prop Sheets, Background Sheet, and Music Brief referenced for this scene.\n\nFOLLOW EXACTLY\n\n\u2022 This scene''s Blueprint\n\u2022 The Character Sheets featured in this scene\n\u2022 The Prop Sheets featured in this scene\n\u2022 This scene''s Background Sheet\n\u2022 The Music Brief\n\nCONTINUITY\n\n\u2022 Character identity\n\u2022 Hair & wardrobe\n\u2022 Props\n\u2022 Backgrounds\n\u2022 Time of day\n\u2022 Weather\n\u2022 Lighting\n\u2022 Camera direction\n\u2022 Screen direction\n\u2022 Dialogue timing\n\u2022 Emotion progression\n\u2022 Branding\n\nCINEMATOGRAPHY\n\n\u2022 Hollywood commercial quality\n\u2022 Premium advertising cinematography\n\u2022 Natural human motion\n\u2022 Realistic facial animation\n\u2022 Accurate lip sync (if dialogue exists)\n\u2022 Correct eye-line\n\u2022 Natural hand interactions\n\u2022 Realistic physics\n\u2022 Smooth camera movement\n\u2022 Consistent color grading\n\u2022 Feature-film lighting\n\u2022 Premium depth of field\n\nEDITING\n\n\u2022 Respect the planned shot duration\n\u2022 Preserve pacing\n\u2022 Match music cues\n\u2022 Match sound effects\n\u2022 Broadcast-ready finish\n\nDO NOT\n\n\u2022 Change story\n\u2022 Add characters\n\u2022 Change wardrobe\n\u2022 Change props\n\u2022 Redesign locations\n\u2022 Change branding\n\nOUTPUT\n\nGenerate ONE polished, commercial-quality video clip for this scene, faithful to its approved Scene Blueprint and the Production Bible."}]}}}')
  ON CONFLICT(stage) DO UPDATE SET config = excluded.config, updated_at = datetime('now');
